function getPhone(val) {
  if (!val) return null;
  if (typeof val === 'object') val = val.id || val.phone || val.number || JSON.stringify(val);
  let s = String(val);
  if (s.includes('wa.me/')) s = s.split('wa.me/')[1].split('?')[0];
  const digits = s.replace(/\D/g, '');
  return (digits.length >= 7 && digits.length <= 15) ? digits : null;
}

