const results = [];
const store = $getWorkflowStaticData('global');
if (!store.history) store.history = [];
if (!store.lastSenders) store.lastSenders = {};

const now = Date.now();
const TTL = 86400000;
const BURST_WINDOW = 30000; // 30 segundos

store.history = store.history.filter(h => now - h.time < TTL);

// Simple fingerprint instead of crypto to avoid module restrictions
function getFingerprint(text) {
  return String(text || "").toLowerCase().replace(/[^a-z0-9]/g, "").substring(0, 120);
}

for (const item of $input.all()) {
  const data = item.json;
  const sender = String(data.final_contact || data.sender_contact || "").replace(/\D/g, "");
  const fp = getFingerprint(data.texto_limpio);

  let isDuplicate = false;

  if (sender && store.lastSenders[sender] && (now - store.lastSenders[sender].time < BURST_WINDOW)) {
    isDuplicate = true;
  }
  if (!isDuplicate) {
    isDuplicate = store.history.some(h => h.fp === fp);
  }

  if (!isDuplicate) {
    store.history.push({ time: now, sender, fp });
    if (sender) store.lastSenders[sender] = { time: now };
    results.push(item);
  }
}
return results;

try {
  const input = $input.first().json;

  let rawText = input.text || input.output || input.result || input.response?.text || input.response || input.data?.text || input.data?.content || input.output?.content || input.content || input.choices?.[0]?.message?.content || "";

  if (!rawText && typeof input === 'object') {
    const deepSearch = JSON.stringify(input);
    const match = deepSearch.match(/"content":"([^"]+)"/);
    if (match) rawText = match[1];
  }

  let cleaned = rawText.replace(/```json/g, '').replace(/```/g, '').trim();
  let jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  if (jsonMatch) jsonMatch[0] = jsonMatch[0].replace(/\n/g, ' ').replace(/\r/g, ' ');

  let jsonStr = jsonMatch ? jsonMatch[0] : "";
  let parsed = {};
  if (!jsonStr) return [{ json: { trash: true, category: 'trash', debug_raw: rawText } }];

  try { parsed = JSON.parse(jsonStr); }
  catch (ex) { return [{ json: { trash: true, category: 'trash' } }]; }

  function cleanContact(value, platform) {
    if (!value || value === "Unknown") return null;
    if (typeof value === 'object') value = value.id || value.phone || value.number || JSON.stringify(value);
    const str = String(value).trim();

    if (platform === 'telegram') {
      // REGLA ESTRICTA: Debe empezar con @ y tener letras. NO IDs.
      if (str.startsWith('@') && /[a-zA-Z]/.test(str)) return str;
      if (/[a-zA-Z]/.test(str) && !/t\.me|http/.test(str)) return '@' + str.replace(/^@/, '');
      return null; // Rechazamos si es solo un ID o no tiene formato de username
    }

    if (/[a-zA-Z]/.test(str)) return str; // Para otros, mantenemos si tiene letras
    const digits = str.replace(/[^0-9]/g, '');
    return digits.length >= 7 ? `+${digits}` : str;
  }

  let normalizedContact = cleanContact(parsed.contact, parsed.platform || input.platform);

  // Si es Telegram y no pudimos normalizar un username @, lo marcamos como basura
  const isTgNoUser = (parsed.platform === 'telegram' || input.platform === 'telegram') && (!normalizedContact || !normalizedContact.startsWith('@'));
  const isTrash = parsed.category === 'trash' || parsed.trash === true || isTgNoUser;

  return [{ json: { ...parsed, contact: normalizedContact, final_contact: normalizedContact, trash: isTrash } }];
} catch(e) { return [{json:{ trash:true, category:'trash', debug_error: e.message }}]; }

const item = $json;
const text = String(item.text_es || "").toLowerCase();
const city = String(item.city || "").trim().toLowerCase();
const category = String(item.category || "").trim().toLowerCase();

const POSITIVE = ["apartamento", "plaza", "agency", "agencia", "club", "booking", "tour", "models", "vacante", "hotel", "cita", "meeting", "встреча", "chica", "girl", "девушка"];
const NEGATIVE = ["crypto", "forex", "casino", "bank", "loan", "call center"];

const positiveHits = POSITIVE.filter(k => text.includes(k)).length;
const negativeHits = NEGATIVE.filter(k => text.includes(k)).length;
const hasGoodCity = !!city && !["global", "unknown", "desconocida", "desconocido"].includes(city);

let reject = false, reason = null;

if (category === "trash") { reject = true; reason = "ai_trash"; }
else if (negativeHits >= 1 && positiveHits === 0) { reject = true; reason = "negative_signal"; }
else if (!hasGoodCity && text.length < 150) { reject = true; reason = "weak_lead"; }
else if (!hasGoodCity && positiveHits === 0 && (item.positiveHits || 0) === 0) { reject = true; reason = "no_signal"; } // Si tiene ciudad válida, lo dejamos pasar aunque no tenga keywords

return { ...item, category: category, looksValuableFinal: !reject, reject_reason_final: reason, postPositiveHits: positiveHits };

const store = $getWorkflowStaticData('global');

if (!store.users) store.users = {};
if (!store.banned) store.banned = {};

const results = [];
const now = Date.now();

// Configuración del sistema de Auto-Ban
const BAN_TIME = 24 * 60 * 60 * 1000; // 24 horas
const MIN_MSGS = 5; // Mínimo de mensajes para evaluar ban
const MAX_BAD_RATIO = 0.7; // Si el 70% o más de sus mensajes son basura (trash), se banea
const WHITELIST = new Set(["346xxxxxxx", "admin_id"]);

for (const item of $input.all()) {
  const data = item.json;
  const sender = String(data.final_contact || data.sender_contact || "unknown");

  // Si está en whitelist, pasa siempre sin contar
  if (WHITELIST.has(sender)) {
    results.push(item);
    continue;
  }

  // Si no existe, inicializar usuario
  if (!store.users[sender]) {
    store.users[sender] = {
      good: 0,
      bad: 0,
      total: 0
    };
  }

  // Revisar si ya está baneado
  if (store.banned[sender]) {
    const ban = store.banned[sender];
    if (now < ban.until) {
      data.looksValuableFinal = false; // Forzamos el bloqueo
      data.reject_reason_final = "user_auto_banned";
      results.push(item);
      continue;
    } else {
      // El ban expiró, le damos otra oportunidad
      delete store.banned[sender];
      store.users[sender] = { good: 0, bad: 0, total: 0 };
    }
  }

  const user = store.users[sender];

  // Decay memory (Olvido progresivo - Mejora aplicada)
  user.good *= 0.95;
  user.bad *= 0.95;
  user.total = user.good + user.bad;
  user.total += 1;

  // Evaluar si este mensaje actual es basura o bueno
  if (data.looksValuableFinal === false || data.trash === true) {
    user.bad += 1;
  } else {
    user.good += 1;
  }

  // Evaluar Ban si supera el umbral de mensajes enviados
  if (user.total >= MIN_MSGS) {
    const ratio = user.bad / user.total;
    if (ratio >= MAX_BAD_RATIO) {
      store.banned[sender] = {
        until: now + BAN_TIME,
        reason: "high_spam_ratio",
        stats: { ...user }
      };
      // Marcamos el mensaje actual para que no pase
      data.looksValuableFinal = false;
      data.reject_reason_final = "user_just_banned";
    }
  }

  results.push(item);
}

return results;

